	idxIter := s.client.Single().Query(ctx, spanner.Statement{
		SQL: `SELECT INDEX_NAME, IS_UNIQUE
			  FROM INFORMATION_SCHEMA.INDEXES
			  WHERE TABLE_NAME = @table AND INDEX_TYPE = 'INDEX'
