	}
	if len(schema.Types) != 1 {
		t.Fatalf("expected 1 type, got %d", len(schema.Types))
	}

	got := schema.Types[0]
	if diff := cmp.Diff([]Field{
		{
			Name:            "RunID",
			ColumnName:      "RunId",
			GoType:          "int64",
			SpannerType:     "INT64",
			BaseSpannerType: "INT64",
			NotNull:         true,
